// Node: Code
// Name: "Clean & Validate Form Data - Dual Output"

// Get form data
const formData = $input.first().json;

// Configuration
const config = {
  minTranscriptLength: 300
};

// Comprehensive transcript cleaner that preserves timing information
function cleanTranscript(transcript) {
  if (!transcript || typeof transcript !== 'string') {
    return { segments: [] };
  }

  let cleaned = transcript;

  // Remove BOM and normalize line endings
  cleaned = cleaned.replace(/^\uFEFF/, '').replace(/\r\n/g, '\n').replace(/\r/g, '\n');

  // Detect format and extract segments
  let format = detectFormat(cleaned);

  switch (format) {
    case 'WEBVTT':
      return cleanWebVTT(cleaned);
    case 'SRT':
      return cleanSRT(cleaned);
    case 'ZOOM':
      return cleanZoomTranscript(cleaned);
    case 'TEAMS':
      return cleanTeamsTranscript(cleaned);
    default:
      return cleanGenericTranscript(cleaned);
  }
}

// Format detection
function detectFormat(text) {
  if (text.match(/^WEBVTT/i)) return 'WEBVTT';
  if (text.match(/^\d+\s*\n\d{2}:\d{2}:\d{2},\d{3}\s*-->\s*\d{2}:\d{2}:\d{2},\d{3}/m)) return 'SRT';
  if (text.includes('-->') && text.match(/\d{2}:\d{2}:\d{2}\.\d{3}/)) return 'WEBVTT';
  if (text.match(/^\d{2}:\d{2}:\d{2}\s+[A-Za-z\s]+:/m)) return 'ZOOM';
  if (text.match(/\[\d{1,2}:\d{2}:\d{2}\s*[AP]M\]/)) return 'TEAMS';
  return 'GENERIC';
}

// Clean WEBVTT format with speaker extraction
function cleanWebVTT(text) {
  const segments = [];
  const lines = text.split('\n');
  let currentSegment = null;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i].trim();

    // Skip WEBVTT header and notes
    if (line === 'WEBVTT' || line.startsWith('NOTE')) continue;

    // Check for timestamp line
    const timestampMatch = line.match(/(\d{2}:\d{2}:\d{2}\.\d{3})\s*-->\s*(\d{2}:\d{2}:\d{2}\.\d{3})/);
    if (timestampMatch) {
      if (currentSegment && currentSegment.text) {
        // Extract speaker from text
        const speakerMatch = currentSegment.text.match(/^([A-Za-z\s\-\.]+?):\s*(.*)$/);
        if (speakerMatch) {
          currentSegment.speaker = speakerMatch[1].trim();
          currentSegment.text = speakerMatch[2].trim();
        }
        segments.push(currentSegment);
      }
      currentSegment = {
        startTime: timestampMatch[1],
        endTime: timestampMatch[2],
        startSeconds: timeToSeconds(timestampMatch[1]),
        endSeconds: timeToSeconds(timestampMatch[2]),
        text: ''
      };
    } else if (currentSegment && line && !line.match(/^\d+$/)) {
      // Add text to current segment
      currentSegment.text += (currentSegment.text ? ' ' : '') + line;
    }
  }

  // Don't forget the last segment
  if (currentSegment && currentSegment.text) {
    const speakerMatch = currentSegment.text.match(/^([A-Za-z\s\-\.]+?):\s*(.*)$/);
    if (speakerMatch) {
      currentSegment.speaker = speakerMatch[1].trim();
      currentSegment.text = speakerMatch[2].trim();
    }
    segments.push(currentSegment);
  }

  return { segments };
}

// Clean SRT format
function cleanSRT(text) {
  const segments = [];
  const blocks = text.split(/\n\n+/);

  blocks.forEach(block => {
    const lines = block.trim().split('\n');
    if (lines.length >= 2) {
      const timestampMatch = lines[1].match(/(\d{2}:\d{2}:\d{2},\d{3})\s*-->\s*(\d{2}:\d{2}:\d{2},\d{3})/);
      if (timestampMatch) {
        const textLines = lines.slice(2).join(' ').trim();
        if (textLines) {
          const segment = {
            startTime: timestampMatch[1].replace(',', '.'),
            endTime: timestampMatch[2].replace(',', '.'),
            startSeconds: timeToSeconds(timestampMatch[1].replace(',', '.')),
            endSeconds: timeToSeconds(timestampMatch[2].replace(',', '.')),
            text: textLines
          };

          // Extract speaker from text
          const speakerMatch = textLines.match(/^([A-Za-z\s\-\.]+?):\s*(.*)$/);
          if (speakerMatch) {
            segment.speaker = speakerMatch[1].trim();
            segment.text = speakerMatch[2].trim();
          }

          segments.push(segment);
        }
      }
    }
  });

  return { segments };
}

// Clean Zoom transcript
function cleanZoomTranscript(text) {
  const segments = [];
  const lines = text.split('\n');
  let currentTime = null;
  let currentSpeaker = null;
  let currentText = '';

  lines.forEach(line => {
    const speakerMatch = line.match(/^(\d{2}:\d{2}:\d{2})\s+([^:]+):\s*(.*)$/);

    if (speakerMatch) {
      if (currentTime && currentText && currentSpeaker) {
        segments.push({
          startTime: currentTime,
          startSeconds: timeToSeconds(currentTime + '.000'),
          speaker: currentSpeaker,
          text: currentText.trim()
        });
      }

      currentTime = speakerMatch[1];
      currentSpeaker = speakerMatch[2].trim();
      currentText = speakerMatch[3];
    } else if (currentTime && line.trim()) {
      currentText += ' ' + line.trim();
    }
  });

  // Last segment
  if (currentTime && currentText && currentSpeaker) {
    segments.push({
      startTime: currentTime,
      startSeconds: timeToSeconds(currentTime + '.000'),
      speaker: currentSpeaker,
      text: currentText.trim()
    });
  }

  return { segments };
}

// Clean Teams transcript
function cleanTeamsTranscript(text) {
  const segments = [];
  const lines = text.split('\n');

  lines.forEach(line => {
    const match = line.match(/\[(\d{1,2}:\d{2}:\d{2}\s*[AP]M)\]\s*([^:]+):\s*(.+)/);
    if (match) {
      segments.push({
        startTime: match[1],
        startSeconds: timeToSeconds(convertTo24Hour(match[1])),
        speaker: match[2].trim(),
        text: match[3].trim()
      });
    }
  });

  return { segments };
}

// Clean generic transcript
function cleanGenericTranscript(text) {
  const segments = [];
  const lines = text.split('\n');
  let currentSpeaker = null;
  let currentText = '';

  lines.forEach(line => {
    line = line.trim();
    if (!line) return;

    // Check for speaker pattern
    const speakerMatch = line.match(/^([A-Za-z0-9\s\-\.]+?):\s*(.*)$/);

    if (speakerMatch) {
      if (currentSpeaker && currentText) {
        segments.push({
          speaker: currentSpeaker,
          text: currentText.trim()
        });
      }

      currentSpeaker = speakerMatch[1].trim();
      currentText = speakerMatch[2];
    } else if (currentSpeaker) {
      currentText += ' ' + line;
    } else {
      // No speaker format, treat as continuous text
      segments.push({
        text: line
      });
    }
  });

  // Last segment
  if (currentSpeaker && currentText) {
    segments.push({
      speaker: currentSpeaker,
      text: currentText.trim()
    });
  }

  return { segments };
}

// Format segments into two outputs
function formatTranscripts(segments) {
  let cleanWithoutTimestamps = '';
  let cleanWithTimestamps = '';

  segments.forEach((segment) => {
    if (segment.speaker) {
      // Version without timestamps
      cleanWithoutTimestamps += `${segment.speaker}: ${segment.text}\n\n`;

      // Version with timestamps
      if (segment.startTime) {
        cleanWithTimestamps += `[${segment.startTime}] ${segment.speaker}: ${segment.text}\n\n`;
      } else {
        cleanWithTimestamps += `${segment.speaker}: ${segment.text}\n\n`;
      }
    } else if (segment.text) {
      // No speaker identified, just add the text
      cleanWithoutTimestamps += `${segment.text}\n\n`;

      if (segment.startTime) {
        cleanWithTimestamps += `[${segment.startTime}] ${segment.text}\n\n`;
      } else {
        cleanWithTimestamps += `${segment.text}\n\n`;
      }
    }
  });

  return {
    withoutTimestamps: cleanWithoutTimestamps.trim(),
    withTimestamps: cleanWithTimestamps.trim()
  };
}

// Helper functions
function timeToSeconds(time) {
  if (!time) return 0;
  const parts = time.split(':');
  if (parts.length === 3) {
    const [hours, minutes, seconds] = parts;
    return parseInt(hours) * 3600 + parseInt(minutes) * 60 + parseFloat(seconds);
  }
  return 0;
}

function convertTo24Hour(time12h) {
  const [time, modifier] = time12h.split(/\s+/);
  let [hours, minutes, seconds] = time.split(':');
  hours = parseInt(hours);

  if (modifier === 'PM' && hours !== 12) {
    hours += 12;
  } else if (modifier === 'AM' && hours === 12) {
    hours = 0;
  }

  return `${hours.toString().padStart(2, '0')}:${minutes}:${seconds || '00'}`;
}

// Main processing
const result = cleanTranscript(formData['Call Transcript'] || '');
const formatted = formatTranscripts(result.segments);

// Validate minimum length
if (formatted.withoutTimestamps.length < config.minTranscriptLength) {
  throw new Error(
    `Transcript too short for meaningful analysis. ` +
    `Please provide at least ${config.minTranscriptLength} characters. ` +
    `Current length: ${formatted.withoutTimestamps.length} characters.`
  );
}

// Validate email
function isValidEmail(email) {
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return emailRegex.test(email);
}

if (!isValidEmail(formData.Email)) {
  throw new Error('Please provide a valid email address');
}

// Format date
function formatDate(dateString) {
  if (!dateString) return new Date().toISOString();
  try {
    const date = new Date(dateString);
    return isNaN(date.getTime()) ? new Date().toISOString() : date.toISOString();
  } catch (e) {
    return new Date().toISOString();
  }
}

// Prepare cleaned data
const cleanedData = {
  // Client Information
  clientInfo: {
    name: (formData['Your Name'] || '').trim(),
    email: formData.Email.trim().toLowerCase(),
    company: (formData['Company Name'] || '').trim()
  },

  // Call Information
  callInfo: {
    salesRep: (formData['Sales Rep Name'] || 'Not specified').trim(),
    prospect: (formData['Prospect Name'] || 'Not specified').trim(),
    callDate: formatDate(formData['Call Date']),
    submittedAt: formData.submittedAt || new Date().toISOString()
  },

  // Two versions of the transcript
  transcriptClean: formatted.withoutTimestamps,
  transcriptWithTimestamps: formatted.withTimestamps,

  // Metadata
  metadata: {
    analysisId: `analysis_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
    formMode: formData.formMode || 'production',
    transcriptStats: {
      length: formatted.withoutTimestamps.length,
      wordCount: formatted.withoutTimestamps.split(/\s+/).filter(word => word.length > 0).length,
      segments: result.segments.length
    }
  }
};

// Validation
const errors = [];
if (!cleanedData.clientInfo.name) errors.push('Name is required');
if (!cleanedData.clientInfo.company) errors.push('Company name is required');

if (errors.length > 0) {
  throw new Error('Validation errors: ' + errors.join(', '));
}

// Return cleaned data
return cleanedData;

// Get just the M4A download URL
const items = $('Zoom Webhook').all();
// Extract the M4A file from the recording files
const recordingFiles = items[0].json.body.payload.object.recording_files;
const m4aFile = recordingFiles.find(file => file.file_type === 'M4A');

if (m4aFile) {
  // Return the M4A file data
  return {
    json: {
      id: m4aFile.id,
      download_url: m4aFile.download_url,
      play_url: m4aFile.play_url,
      file_size: m4aFile.file_size,
      recording_start: m4aFile.recording_start,
      recording_end: m4aFile.recording_end,
      file_extension: m4aFile.file_extension,
      status: m4aFile.status
    }
  };
} else {
  // No M4A file found
  return {
    json: {
      error: "No M4A file found in the recording"
    }
  };
}

// Get input data
const items = $input.all();
const data = items[0].json;

// Determine the source based on available fields
const isFormSubmission = !!data.SubmissionName;
const isZoomRecording = !!data['Call UUID'];

// Normalize the data structure
let normalizedData = {
  // Common fields
  transcript: data.Transcript || '',

  // Map different field names to consistent ones
  name: data.SubmissionName || data.Name || '',
  email: data.Email || data["Host's Email"] || '',  // Fixed: Check both field names
  company: data.Company || 'AI Acquisition', // Default if not in Zoom
  salesRep: data.SalesRep || data["Host's Email"] || '',
  prospect: data.Prospect || extractProspectFromName(data.Name) || '',
  callDate: data.CallDate || data['Call date'] || '',

  // Source-specific fields
  source: isFormSubmission ? 'form_submission' : 'zoom_recording',
  submissionDate: data.SubmissionDate || null,
  callUUID: data['Call UUID'] || null,
  duration: data.Duration || null,
  videoLink: data['Video Recording Link'] || null,
  audioLink: data['Audio Recording Link'] || null,

  // Keep track of what we have
  hasTranscript: !!(data.Transcript && data.Transcript.length > 0),
  hasRecordingLinks: !!(data['Video Recording Link'] || data['Audio Recording Link'])
};

// Helper function to extract prospect name from Zoom topic
function extractProspectFromName(name) {
  if (!name) return '';
  // Extract name before colon (e.g., "Todd Sandberg: AI Business Strategy Call" -> "Todd Sandberg")
  const match = name.match(/^([^:]+):/);
  return match ? match[1].trim() : '';
}

return {
  json: normalizedData
};

// Add emojis and format the extracted data for display
const items = $('Format the Analysis').all();
const data = items[0].json.output || items[0].json;

// Get the GID from the Set node
const SUMMARY_SHEET_GID = $input.first().json.GID || "123456789";

// Get the raw analysis from the first LLM
const rawAnalysis = $('Summarize the call').first().json.output || 
                   $('Summarize the call').first().json.text || 
                   $('Summarize the call').first().json || 
                   '';

// Helper function to add emojis to sections
function formatWithEmojis(extractedData) {
  const formatted = JSON.parse(JSON.stringify(extractedData)); // Deep clone

  // Add emojis to category analysis
  formatted.categoryAnalysis = formatted.categoryAnalysis.map(category => ({
    ...category,
    categoryDisplay: `${getCategoryEmoji(category.category)} ${category.category}`,
    whatWorkedDisplay: category.whatWorked.map(item => `✅ ${item}`),
    whatNeededImprovementDisplay: category.whatNeededImprovement.map(item => `❌ ${item}`)
  }));

  // Add emojis to final takeaways
  formatted.finalTakeawaysDisplay = {
    biggestStrength: `🔥 Biggest Strength: ${formatted.finalTakeaways.biggestStrength}`,
    biggestWeakness: `⚠️ Biggest Weakness: ${formatted.finalTakeaways.biggestWeakness}`,
    gameChangerForNextCall: `🎯 Game-Changer for Next Call: ${formatted.finalTakeaways.gameChangerForNextCall}`,
    additionalNotes: formatted.finalTakeaways.additionalNotes ? `📝 Additional Notes: ${formatted.finalTakeaways.additionalNotes}` : null
  };

  // Add emojis to objections
  formatted.objectionsDisplay = formatted.objections.map((obj, index) => ({
    ...obj,
    objectionDisplay: `🚧 Objection ${index + 1}: ${obj.objection}`
  }));

  return formatted;
}

// Helper function to get category-specific emojis
function getCategoryEmoji(category) {
  const emojiMap = {
    'Call Control': '🎯',
    'Discovery Depth': '🔍',
    'Belief Shifting': '💡',
    'Objection Handling': '🛠️',
    'Pitch Effectiveness': '📊',
    'Closing Strength': '💪'
  };
  return emojiMap[category] || '📌';
}

// Helper function for performance indicators
function getPerformanceIndicator(score) {
  if (score >= 9) return '🟢 Excellent';
  if (score >= 7) return '🟡 Good';
  if (score >= 5) return '🟠 Average';
  return '🔴 Needs Work';
}

// Format the data with emojis
const formattedData = formatWithEmojis(data);

// Calculate additional metrics
const avgScore = formattedData.categoryAnalysis.reduce((sum, cat) => sum + cat.score, 0) / formattedData.categoryAnalysis.length;
const performanceLevel = getPerformanceIndicator(avgScore);
const objectionHandlingRate = data.objections.length > 0 
  ? Math.round((data.objections.filter(obj => obj.wasPostHandled === 'Yes' || obj.wasPostHandled === true).length / data.objections.length) * 100)
  : 100;

// Get individual category scores
const getScoreByCategory = (categoryName) => {
  const cat = formattedData.categoryAnalysis.find(c => c.category === categoryName);
  return cat ? cat.score : 0;
};

// Get metadata from original clean data if available
const metadata = $('Clean Data from Both Routes').first().json || {};

// CREATE A UNIQUE ID FOR THIS CALL
const uniqueId = `${data.callMetadata.salesRep.split('@')[0]}_${new Date(data.callMetadata.callDate).getTime()}`;

// CREATE SUMMARY DATA
const summaryData = {
  "🔑 Summary ID": uniqueId,
  "📅 Date": new Date(data.callMetadata.callDate).toLocaleDateString(),
  "👤 Rep": data.callMetadata.salesRep.split('@')[0],
  "🎯 Prospect": data.callMetadata.prospect,
  "✅ What Worked": formattedData.categoryAnalysis.map(cat => 
    `${cat.categoryDisplay}:\n${cat.whatWorked.map(item => `• ${item}`).join('\n')}`
  ).join('\n\n'),
  "❌ Areas to Improve": formattedData.categoryAnalysis.map(cat => 
    `${cat.categoryDisplay}:\n${cat.whatNeededImprovement.map(item => `• ${item}`).join('\n')}`
  ).join('\n\n'),
  "🔥 Key Strength": data.finalTakeaways.biggestStrength,
  "⚠️ Key Weakness": data.finalTakeaways.biggestWeakness,
  "🎯 Next Call Action": data.finalTakeaways.gameChangerForNextCall,
  "📄 Full Analysis": rawAnalysis
};

// CREATE MAIN DATA WITH DYNAMIC HYPERLINK
const mainData = {
  "📅 Call Date": new Date(data.callMetadata.callDate).toLocaleDateString(),
  "👤 Sales Rep": data.callMetadata.salesRep.split('@')[0],
  "🎯 Prospect": data.callMetadata.prospect,
  "🏢 Company": data.callMetadata.company,
  "⏱️ Duration": data.callMetadata.duration,
  "📞 Source": data.callMetadata.source,
  "🏆 Total Score": `${data.scores.totalScore.score}/${data.scores.totalScore.maxScore} (${data.scores.totalScore.percentage}%)`,
  "📊 Performance Level": performanceLevel,
  "✅ Deal Closed": data.outcome.dealClosed === 'true' ? 'Yes' : 'No',
  "💰 Deal Value": data.outcome.dealValue ? `$${parseInt(data.outcome.dealValue.replace(/,/g, '')).toLocaleString()}` : 'N/A',
  "🎯 Call Control Score": `${getScoreByCategory('Call Control')}/10`,
  "🔍 Discovery Depth Score": `${getScoreByCategory('Discovery Depth')}/10`,
  "💡 Belief Shifting Score": `${getScoreByCategory('Belief Shifting')}/10`,
  "🛠️ Objection Handling Score": `${getScoreByCategory('Objection Handling')}/10`,
  "📊 Pitch Effectiveness Score": `${getScoreByCategory('Pitch Effectiveness')}/10`,
  "💪 Closing Strength Score": `${getScoreByCategory('Closing Strength')}/10`,
  "📈 Average Score": `${Math.round(avgScore * 10) / 10}/10`,
  "📋 View Summary": `=HYPERLINK("#gid=${SUMMARY_SHEET_GID}&range=A"&MATCH("${uniqueId}",Summaries!A:A,0),"📋 Click for Details")`,
  "🚧 # of Objections": data.objections.length,
  "📊 Objection Handling Rate %": `${objectionHandlingRate}%`,
  "➡️ Next Steps": data.outcome.nextSteps || 'N/A',
  "🔑 Call UUID": metadata.callUUID || 'N/A',
  "🎥 Video Link": metadata.videoLink || 'N/A',
  "🎵 Audio Link": metadata.audioLink || 'N/A',
  "📝 Additional Notes": data.finalTakeaways.additionalNotes || 'N/A',
  "🔑 Summary ID": uniqueId
};

// Return both outputs
return {
  json: {
    summaryData: summaryData,
    mainData: mainData,
    uniqueId: uniqueId
  }
};

// Get the recording timestamps from the input data
const inputData = $input.first().json;
const recordingStart = new Date(inputData.CallStart);
const recordingEnd = new Date(inputData.CallEnd);

// Calculate duration in minutes
const durationMinutes = (recordingEnd - recordingStart) / (1000 * 60);

// Get minimum duration from the input
const minDuration = inputData["MinimumDuration(Mins)"];

// Return ALL original data plus duration check results
return {
  call_duration: Math.round(durationMinutes),
  minimum_duration: minDuration,
  process_call: durationMinutes >= minDuration,
  duration_message: `Call duration: ${Math.round(durationMinutes)} minutes (minimum: ${minDuration} minutes)`,

};

